import {
  useTranslation as useTranslationOriginal,
  UseTranslationResponse,
} from "react-i18next";
import type enTranslations from "./translations/en";

type TranslationKeys = typeof enTranslations;

export function useTranslation(
  ns?: string | string[]
): UseTranslationResponse<string, TranslationKeys> {
  return useTranslationOriginal(ns) as UseTranslationResponse<
    string,
    TranslationKeys
  >;
}

export type { TranslationKeys };
